import{_ as r,o as t,c as o,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const E=JSON.parse('{"title":"E.G.O.乌瞰刀","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/E.G.O.乌瞰刀.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/E.G.O.乌瞰刀.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/白刃类/E.G.O.乌瞰刀.md"};function p(_,a,l,i,c,h){return t(),o("div",null,[...a[0]||(a[0]=[e("h1",{id:"e-g-o-乌瞰刀",tabindex:"-1"},[n("E.G.O.乌瞰刀 "),e("a",{class:"header-anchor",href:"#e-g-o-乌瞰刀","aria-label":'Permalink to "E.G.O.乌瞰刀"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风029特别节愚人版")])])],-1),s('<h1 id="e-g-o-乌瞰刀-1" tabindex="-1">E.G.O.乌瞰刀 <a class="header-anchor" href="#e-g-o-乌瞰刀-1" aria-label="Permalink to &quot;E.G.O.乌瞰刀&quot;">​</a></h1><p>E.G.O.乌瞰刀<br> ZAYIN级<br> D+500<br> “告诉我你为‘理想’作何定义。”<br> 解析等级I：<br> 当你进行一种你已有的白刃标准动作攻击时，你可以消耗3点意志，这次攻击将附带E.G.O.乌瞰刀。<br> 仅这一次攻击期间，你的武器将转变为由漆黑的鸦羽构成，一切数据不变，在攻击后将绽放出飞舞的黑羽，这次攻击后，持续到你的下个回合行动开始前，你的先攻提升16点。</p><p>解析等级II：支付D+500升级，差升为C级技艺，获得2点自由属性点，此时的效果更改为：消耗4点意志附带E.G.O.乌瞰刀，攻击后获得16点先攻，持续到你的下个回合行动开始前。<br> 你可以选择将从E.G.O.乌瞰刀中获得的先攻提升给予以自身为圆心，以7米为半径的圆形范围内的所有友军而非自身。</p><p>解析等级III：在购买【解析等级II】后，支付10xp研发，如同兑换技艺般获得2点自由属性点，你可共享的范围提升至15米半径圆，获得的先攻提升至18点，并且在给予队友先攻加成时自身也会获得先攻加成。</p><p>解析等级VI：在购买【解析等级III】后支付D+500升级，差升为B级技艺，获得2点自由属性点，此时的效果更改为：<br> 消耗8点意志，使得这次攻击附带E.G.O.乌瞰刀，自身周围15米半径范围内的包括自身在内的友军获得18+传奇决心*4点先攻，获得收益的友军将在攻击时额外获得【高速2】，效果持续到你的下个回合行动开始前。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const I=r(d,[["render",p]]);export{E as __pageData,I as default};
